attr_reader :request

def initialize(user = nil, request = nil)
  @user = user.presence || Guardian::AnonymousUser.new
  @request = request
end

def user
  @user.presence
end
alias current_user user

def anonymous?
  !authenticated?
end

def authenticated?
  @user.present?
end

def is_admin?
  @user.admin?
end

def is_staff?
  @user.staff?
end

def is_moderator?
  @user.moderator?
end

def is_whisperer?
  @user.whisperer?
end

def is_category_group_moderator?(category)
  return false if !category
  return false if !category_group_moderation_allowed?

  @moderated_category_ids ||= category_group_moderator_scope.pluck(:id).to_set
  @moderated_category_ids.include?(category.id)
end

def is_silenced?
  @user.silenced?
end

def is_developer?
  @user &&
    (
      Rails.env.development? || (is_admin? && Developer.user_ids.include?(@user.id)) ||
        (
          Rails.configuration.respond_to?(:developer_emails) &&
            Rails.configuration.developer_emails.include?(@user.email)
        )
    )
end

def is_staged?
  @user.staged?
end

def is_anonymous?
  @user.anonymous?
end

# Can the user see the object?
def can_see?(obj)
  if obj
    see_method = method_name_for :see, obj
    see_method && public_send(see_method, obj)
  end

